mapper.update:
UPDATE student_archive
file_type = #{fileType}, file_name = #{fileName}, file_url = #{fileUrl}, remark = #{remark}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT sa.id, sa.student_id AS studentId, sa.file_type AS fileType, sa.file_name AS fileName, sa.file_url AS fileUrl, sa.upload_time AS uploadTime, sa.remark, sa.status, su.name AS studentName, su.student_user_id AS studentUserId, m.name AS majorName, c.name AS className FROM student_archive sa LEFT JOIN student_users su ON sa.student_id = su.id LEFT JOIN major m ON su.major_id = m.id LEFT JOIN class c ON su.class_id = c.id
su.name LIKE CONCAT('%', #{studentName}, '%')
AND sa.file_type = #{fileType}
AND sa.status = #{status}
ORDER BY sa.upload_time DESC
